  lamp:{    name:'headlamp',  desc:'a small headlamp. night is where the mind goes bad; light is purpose, and purpose is heat.' },
  iodine:{  name:'iodine tabs', desc:'water purification tablets. useless against salt. everywhere else, they turn fear into a drink.' },
  bars:{    name:'two energy bars', desc:'six hundred calories of pocket lint flavor. out there, a feast with two courses.' },
