/* the pocket kit: what you happened to be carrying when the world turned */
const loadout = ['lighter','cord','lamp','iodine','bars','wool'];

/* ---------------- log (journal collectibles) ---------------- */
const logs = {
  l_triage:{ src:'The White Mile', line:'Bleeding first. Everything else second. I wrote it on the back of my hand so the cold couldn’t make me forget.' },
  l_firstnight:{ src:'The White Mile', line:'It isn’t the crash that kills you out here. It’s the first night, and whether you built for it before dark.' },
  l_smalltasks:{ src:'a survivor’s log', line:'I stopped looking at the whole thing. Just the next stick. Just the next sip. Just the next hour. You can always do the next small thing.' },
  l_ration:{ src:'a survivor’s log', line:'Thirst lies. It tells you to drink it all, or to drink the wrong thing. I made a rule and gave the rule my trust instead of my mouth.' },
  l_still:{ src:'The Raft', line:'Drop by drop the still gave me water out of the sea that would have killed me straight. Patience, distilled.' },
  l_routine:{ src:'The Raft', line:'The ship didn’t turn. I wrote it down, and then I did my chores anyway. The routine is a handrail in the dark.' },
  l_donttell:{ src:'The Pinch', line:'Nobody knew where I’d gone. Nobody. If I get out of this, someone will always know. That’s the whole lesson, and it cost me an arm.' },
  l_thechild:{ src:'The Pinch', line:'I saw a boy I hadn’t met yet — mine — and I was lifting him with one arm. I decided he was real. That decision is the only reason I’m writing this.' },
  l_reason:{ src:'a survivor’s log', line:'You don’t survive for yourself. You survive so you can get back to someone. Name them. Hold the name where the cold can’t reach it.' },
  l_stop:{ src:'The Trailhead', line:'STOP. Stop. Think. Observe. Plan. The hardest part is the first letter. Everything in you wants to keep walking, and the walking is what kills.' },
  l_findable:{ src:'The Trailhead', line:'I stopped hiding from the thing hunting me and started performing for the thing looking for me. Being findable is a job. I did the job.' },
  l_giardia:{ src:'The Trailhead', line:'The parasite is a next-month problem. The thirst is a today problem. I knelt down and I drank.' },
  l_twentymin:{ src:'The Crevasse', line:'The voice said: reach that rock in twenty minutes. Not “reach camp.” Not “survive.” That rock. Twenty minutes. I could always do twenty minutes.' },
  l_downisout:{ src:'The Crevasse', line:'Up was impossible and waiting was dying, so down stopped being the wrong direction. When you cannot go back the way you came, the dark is a door.' },
  l_nightmove:{ src:'The Furnace', line:'The desert is crossed at night and survived at noon. Get those backwards once — just once — and it keeps the difference.' },
};

/* ---------------- the real ones ---------------- */
const reals = {
  koepcke:{ name:'Juliane Koepcke', what:'sole survivor of LANSA Flight 508, 1971',
    body:'A lightning strike tore her plane apart over the Peruvian Amazon and she fell two miles, still strapped to her seat. She woke alone in the rainforest with a broken collarbone. Remembering her father’s advice, she <b>found a creek and followed the moving water downstream</b> — small streams to larger ones, where people live. After <b>eleven days</b>, half-starved and with maggots in her arm, she reached a boat and a hut. Loggers found her hours later. Following water down is exactly how people get out of trackless country.' },
  callahan:{ name:'Steven Callahan', what:'76 days adrift in the Atlantic, 1982',
    body:'His sloop was holed by something in the night — likely a whale — and sank in minutes. He got into a <b>five-foot inflatable raft</b> with a ditch bag. For <b>seventy-six days</b> he ran <b>solar stills</b> for water, speared dorado with a jury-rigged spear, endured shark bumps and punctures and salt sores, and kept a disciplined routine. An <b>ecosystem grew under his raft</b>; birds gathered over it; and it was those birds that drew fishermen to him at last, near the Caribbean. He walked off the boat on his own feet.' },
  ralston:{ name:'Aron Ralston', what:'127 hours pinned in Blue John Canyon, 2003',
    body:'Canyoneering alone, he dislodged an 800-pound boulder that crushed his right wrist against the wall. <b>He had told no one where he was going.</b> For five days he rationed about <b>350 ml of water</b>, then his own urine, chipping uselessly at the rock, filming goodbyes, carving his name and a death date. Then he had a vision of <b>a future child</b> — and, on the fifth day, he <b>levered his forearm until the bones snapped and cut through the rest with a dull multitool</b>. Then he rappelled 65 feet and hiked seven miles until other hikers found him.' },
  eller:{ name:'Amanda Eller', what:'17 days lost in the Makawao Forest, Maui, 2019',
    body:'A yoga instructor went for a three-mile hike on a marked trail and stepped off it to rest. Walking back, she chose the direction she was <b>certain</b> was right — and it wasn’t. She spent <b>seventeen days</b> in the ravines: following drainages, drinking stream water, eating berries and moths, losing her shoes to a flash flood, fracturing her leg. She stayed near water and open ground, and on day 17 a <b>search helicopter</b> — funded by friends who refused to stop — spotted her waving from a creek bed between two waterfalls. She said afterward the turning point was a choice: <b>“It was a choice to live, and I had to keep making it.”</b>' },
  simpson:{ name:'Joe Simpson', what:'the rope, Siula Grande, 1985 — “Touching the Void”',
    body:'Descending a 21,000-foot Andean peak, Simpson shattered his leg — the tibia driven up through the knee. His partner Simon Yates lowered him 3,000 feet down the storm-blasted face on knotted ropes, until Simpson went over an overhang into space, and Yates, being dragged from the mountain, <b>cut the rope</b>. Simpson fell into a crevasse — and lived, on a snow bridge. Unable to climb out, he did the unthinkable: <b>abseiled deeper into the dark</b>, found a ramp of snow, and crawled out. Then, with no water and one leg, he crawled and hopped <b>five miles in three and a half days</b>, driven by a voice in his head that set him <b>twenty-minute goals</b> — reaching camp, delirious, hours before Yates broke it down and left.' },
  prosperi:{ name:'Mauro Prosperi', what:'nine days lost in the Sahara, 1994',
    body:'A police officer running the Marathon des Sables was swallowed by an eight-hour sandstorm — and kept moving. When it cleared, he was off the course and running the wrong way. He survived <b>nine days and nearly 300 kilometers</b>: sheltering in a ruined shrine, drinking his own stored urine and <b>the blood of bats</b>, burning his pack when a search plane passed without seeing him, eating snakes and lizards raw, and finally navigating as nomads taught racers — <b>by the dunes and the dawn</b> — until he found goat tracks, then a shepherd girl, then a Berber camp, 181 miles into Algeria. He had lost 35 pounds. He went back and ran the race again.' },
  mind:{ name:'The ones who come back', what:'Laurence Gonzales, “Deep Survival” · History’s “Alone”',
    body:'Across every real case, the survivors are rarely the strongest or the best-equipped. They’re the ones who <b>don’t panic</b>, who <b>break the impossible into small doable tasks</b>, who <b>accept the reality they’re in</b> instead of the one they wanted, and who hold onto a <b>reason to live</b> — a person to get back to. On the show <em>Alone</em>, the body can go for weeks; it’s almost always the <b>mind that taps out first</b>. Survival is a decision you make over and over, in the cold, with no one watching.' },
};

